package com.wallet.apigateway.security;

import io.jsonwebtoken.Claims;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.springframework.cloud.gateway.filter.GatewayFilterChain;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.mock.http.server.reactive.MockServerHttpRequest;
import org.springframework.mock.web.server.MockServerWebExchange;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Mono;

import java.util.concurrent.atomic.AtomicReference;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

class JwtAuthGlobalFilterTest {

    private JwtTokenValidator jwtTokenValidator;
    private JwtAuthGlobalFilter filter;

    @BeforeEach
    void setUp() {
        jwtTokenValidator = mock(JwtTokenValidator.class);
        filter = new JwtAuthGlobalFilter(jwtTokenValidator);
    }

    @Test
    void filter_withPublicPath_skipsAuthentication() {
        GatewayFilterChain chain = mock(GatewayFilterChain.class);
        when(chain.filter(any())).thenReturn(Mono.empty());

        MockServerWebExchange exchange = MockServerWebExchange.from(MockServerHttpRequest.get("/swagger-ui/index.html").build());

        filter.filter(exchange, chain).block();

        verify(chain).filter(any());
        assertThat(exchange.getResponse().getStatusCode()).isNull();
    }

    @Test
    void filter_withoutAuthorization_returnsUnauthorized() {
        GatewayFilterChain chain = mock(GatewayFilterChain.class);
        MockServerWebExchange exchange = MockServerWebExchange.from(MockServerHttpRequest.get("/api/wallet/balance").build());

        filter.filter(exchange, chain).block();

        assertThat(exchange.getResponse().getStatusCode()).isEqualTo(HttpStatus.UNAUTHORIZED);
    }

    @Test
    void filter_withNonAdminOnAdminPath_returnsForbidden() {
        GatewayFilterChain chain = mock(GatewayFilterChain.class);
        when(chain.filter(any())).thenReturn(Mono.empty());

        Claims claims = mock(Claims.class);
        when(claims.get("role", String.class)).thenReturn("USER");
        when(claims.get("userId")).thenReturn(22L);
        when(claims.getSubject()).thenReturn("bob");

        when(jwtTokenValidator.validateAndGetClaims("valid-token")).thenReturn(claims);

        MockServerWebExchange exchange = MockServerWebExchange.from(
                MockServerHttpRequest.get("/api/admin/campaigns")
                        .header(HttpHeaders.AUTHORIZATION, "Bearer valid-token")
                        .build()
        );

        filter.filter(exchange, chain).block();

        assertThat(exchange.getResponse().getStatusCode()).isEqualTo(HttpStatus.FORBIDDEN);
    }

    @Test
    void filter_withValidToken_mutatesHeadersAndContinues() {
        AtomicReference<ServerWebExchange> captured = new AtomicReference<>();
        GatewayFilterChain chain = exchange -> {
            captured.set(exchange);
            return Mono.empty();
        };

        Claims claims = mock(Claims.class);
        when(claims.get("role", String.class)).thenReturn("USER");
        when(claims.get("userId")).thenReturn(44L);
        when(claims.getSubject()).thenReturn("charlie");

        when(jwtTokenValidator.validateAndGetClaims("ok-token")).thenReturn(claims);

        MockServerWebExchange exchange = MockServerWebExchange.from(
                MockServerHttpRequest.get("/api/wallet/balance")
                        .header(HttpHeaders.AUTHORIZATION, "Bearer ok-token")
                        .build()
        );

        filter.filter(exchange, chain).block();

        assertThat(captured.get()).isNotNull();
        assertThat(captured.get().getRequest().getHeaders().getFirst("X-Authenticated-User")).isEqualTo("charlie");
        assertThat(captured.get().getRequest().getHeaders().getFirst("X-Authenticated-Role")).isEqualTo("USER");
        assertThat(captured.get().getRequest().getHeaders().getFirst("X-Authenticated-UserId")).isEqualTo("44");
    }
}

package com.wallet.apigateway.security;

import io.jsonwebtoken.Claims;
import io.jsonwebtoken.JwtException;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.io.Encoders;
import io.jsonwebtoken.security.Keys;
import org.junit.jupiter.api.Test;

import javax.crypto.SecretKey;
import java.nio.charset.StandardCharsets;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

class JwtTokenValidatorTest {

    private static final String RAW_SECRET = "01234567890123456789012345678901";
    private static final String BASE64_SECRET = Encoders.BASE64.encode(RAW_SECRET.getBytes(StandardCharsets.UTF_8));

    @Test
    void validateAndGetClaims_withValidToken_returnsClaims() {
        SecretKey key = Keys.hmacShaKeyFor(RAW_SECRET.getBytes(StandardCharsets.UTF_8));
        String token = Jwts.builder()
                .subject("alice")
                .claim("role", "USER")
                .claim("userId", 15)
                .signWith(key)
                .compact();

        JwtTokenValidator validator = new JwtTokenValidator(BASE64_SECRET);
        Claims claims = validator.validateAndGetClaims(token);

        assertThat(claims.getSubject()).isEqualTo("alice");
        assertThat(claims.get("role", String.class)).isEqualTo("USER");
    }

    @Test
    void validateAndGetClaims_withBlankToken_throwsJwtException() {
        JwtTokenValidator validator = new JwtTokenValidator(BASE64_SECRET);

        assertThatThrownBy(() -> validator.validateAndGetClaims(" "))
                .isInstanceOf(JwtException.class)
                .hasMessageContaining("missing");
    }

    @Test
    void constructor_withInvalidBase64Secret_throwsIllegalStateException() {
        assertThatThrownBy(() -> new JwtTokenValidator("not-base64"))
                .isInstanceOf(RuntimeException.class)
                .hasMessageContaining("Illegal base64");
    }
}

package com.wallet.apigateway.security;

import org.junit.jupiter.api.Test;
import org.springframework.cloud.gateway.filter.GatewayFilterChain;
import org.springframework.http.HttpStatus;
import org.springframework.mock.http.server.reactive.MockServerHttpRequest;
import org.springframework.mock.web.server.MockServerWebExchange;
import reactor.core.publisher.Mono;

import java.net.InetSocketAddress;
import java.util.concurrent.atomic.AtomicInteger;

import static org.assertj.core.api.Assertions.assertThat;

class SimpleRateLimitFilterTest {

    @Test
    void filter_excludedPath_allowsRequest() {
        SimpleRateLimitFilter filter = new SimpleRateLimitFilter(1);
        AtomicInteger chainCount = new AtomicInteger(0);
        GatewayFilterChain chain = exchange -> {
            chainCount.incrementAndGet();
            return Mono.empty();
        };

        MockServerWebExchange exchange = MockServerWebExchange.from(MockServerHttpRequest.get("/").build());

        filter.filter(exchange, chain).block();

        assertThat(chainCount.get()).isEqualTo(1);
        assertThat(exchange.getResponse().getStatusCode()).isNull();
    }

    @Test
    void filter_whenLimitExceeded_returns429() {
        SimpleRateLimitFilter filter = new SimpleRateLimitFilter(1);
        GatewayFilterChain chain = exchange -> Mono.empty();

        MockServerHttpRequest firstReq = MockServerHttpRequest.get("/api/wallet/balance")
                .remoteAddress(new InetSocketAddress("127.0.0.1", 7777))
                .build();
        MockServerHttpRequest secondReq = MockServerHttpRequest.get("/api/wallet/balance")
                .remoteAddress(new InetSocketAddress("127.0.0.1", 7777))
                .build();

        MockServerWebExchange first = MockServerWebExchange.from(firstReq);
        MockServerWebExchange second = MockServerWebExchange.from(secondReq);

        filter.filter(first, chain).block();
        filter.filter(second, chain).block();

        assertThat(first.getResponse().getStatusCode()).isNull();
        assertThat(second.getResponse().getStatusCode()).isEqualTo(HttpStatus.TOO_MANY_REQUESTS);
        assertThat(second.getResponse().getHeaders().getFirst("Retry-After")).isEqualTo("60");
    }
}

