package com.wallet.transaction.exception;

import jakarta.servlet.http.HttpServletRequest;
import org.junit.jupiter.api.Test;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.mock.web.MockHttpServletRequest;

import static org.assertj.core.api.Assertions.assertThat;

class GlobalExceptionHandlerTest {

    private final GlobalExceptionHandler handler = new GlobalExceptionHandler();

    @Test
    void handleBadRequest_mapsTo400() {
        HttpServletRequest request = request("/transactions/topup");

        ResponseEntity<ApiError> response = handler.handleBadRequest(
                new IllegalArgumentException("bad payload"), request
        );

        assertThat(response.getStatusCode()).isEqualTo(HttpStatus.BAD_REQUEST);
        assertThat(response.getBody()).isNotNull();
        assertThat(response.getBody().message()).isEqualTo("bad payload");
        assertThat(response.getBody().path()).isEqualTo("/transactions/topup");
    }

    @Test
    void handleConflict_mapsIdempotencyErrorTo409() {
        HttpServletRequest request = request("/transactions/transfer");

        ResponseEntity<ApiError> response = handler.handleConflict(
                new IdempotencyConflictException("already used"), request
        );

        assertThat(response.getStatusCode()).isEqualTo(HttpStatus.CONFLICT);
        assertThat(response.getBody()).isNotNull();
        assertThat(response.getBody().message()).isEqualTo("already used");
    }

    @Test
    void handleGeneric_mapsTo500() {
        HttpServletRequest request = request("/transactions/statement");

        ResponseEntity<ApiError> response = handler.handleGeneric(new RuntimeException("oops"), request);

        assertThat(response.getStatusCode()).isEqualTo(HttpStatus.INTERNAL_SERVER_ERROR);
        assertThat(response.getBody()).isNotNull();
        assertThat(response.getBody().message()).isEqualTo("oops");
    }

    private HttpServletRequest request(String uri) {
        MockHttpServletRequest request = new MockHttpServletRequest();
        request.setRequestURI(uri);
        return request;
    }
}

package com.wallet.transaction.repository;

import com.wallet.transaction.entity.Dispute;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;

import java.time.LocalDateTime;

import static org.assertj.core.api.Assertions.assertThat;

@DataJpaTest(properties = {
        "spring.jpa.database-platform=org.hibernate.dialect.H2Dialect",
        "spring.jpa.properties.hibernate.dialect=org.hibernate.dialect.H2Dialect",
        "spring.cloud.config.enabled=false",
        "spring.cloud.config.import-check.enabled=false",
        "spring.cloud.config.fail-fast=false",
        "spring.config.import=optional:configserver:",
        "eureka.client.enabled=false"
})
class DisputeRepositoryTest {

    @Autowired
    private DisputeRepository disputeRepository;

    @Test
    void findByStatusOrderByCreatedAtDesc_returnsNewestFirst() {
        Dispute older = saveDispute(4L, "OPEN", LocalDateTime.now().minusHours(2));
        Dispute newer = saveDispute(4L, "OPEN", LocalDateTime.now().minusHours(1));

        assertThat(disputeRepository.findByStatusOrderByCreatedAtDesc("OPEN"))
                .extracting(Dispute::getId)
                .containsExactly(newer.getId(), older.getId());
    }

    @Test
    void findByUserIdOrderByCreatedAtDesc_filtersByUser() {
        saveDispute(20L, "OPEN", LocalDateTime.now().minusHours(2));
        saveDispute(21L, "OPEN", LocalDateTime.now().minusHours(1));

        assertThat(disputeRepository.findByUserIdOrderByCreatedAtDesc(20L)).hasSize(1);
    }

    private Dispute saveDispute(Long userId, String status, LocalDateTime createdAt) {
        Dispute dispute = new Dispute();
        dispute.setTransactionId(100L);
        dispute.setUserId(userId);
        dispute.setReason("test");
        dispute.setStatus(status);
        dispute.setEscalated(false);
        dispute.setCreatedAt(createdAt);
        dispute.setUpdatedAt(createdAt);
        return disputeRepository.save(dispute);
    }
}

package com.wallet.transaction.repository;

import com.wallet.transaction.entity.EntryType;
import com.wallet.transaction.entity.LedgerEntry;
import com.wallet.transaction.entity.Transaction;
import com.wallet.transaction.entity.TransactionStatus;
import com.wallet.transaction.entity.TransactionType;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;

import java.math.BigDecimal;
import java.time.LocalDateTime;

import static org.assertj.core.api.Assertions.assertThat;

@DataJpaTest(properties = {
        "spring.jpa.database-platform=org.hibernate.dialect.H2Dialect",
        "spring.jpa.properties.hibernate.dialect=org.hibernate.dialect.H2Dialect",
        "spring.cloud.config.enabled=false",
        "spring.cloud.config.import-check.enabled=false",
        "spring.cloud.config.fail-fast=false",
        "spring.config.import=optional:configserver:",
        "eureka.client.enabled=false"
})
class LedgerEntryRepositoryTest {

    @Autowired
    private LedgerEntryRepository ledgerEntryRepository;

    @Autowired
    private TransactionRepository transactionRepository;

    @Test
    void calculateBalance_combinesCreditAndDebit() {
        Transaction transaction = saveTransaction("ledger-key-1");
        saveEntry(transaction, 4L, EntryType.CREDIT, new BigDecimal("120.00"), LocalDateTime.now().minusHours(2));
        saveEntry(transaction, 4L, EntryType.DEBIT, new BigDecimal("20.00"), LocalDateTime.now().minusHours(1));

        assertThat(ledgerEntryRepository.calculateBalance(4L)).isEqualByComparingTo("100.00");
    }

    @Test
    void calculateBalanceBefore_respectsCutoffTime() {
        Transaction transaction = saveTransaction("ledger-key-2");
        LocalDateTime pivot = LocalDateTime.now().minusMinutes(30);
        saveEntry(transaction, 8L, EntryType.CREDIT, new BigDecimal("70.00"), pivot.minusMinutes(10));
        saveEntry(transaction, 8L, EntryType.DEBIT, new BigDecimal("20.00"), pivot.plusMinutes(10));

        assertThat(ledgerEntryRepository.calculateBalanceBefore(8L, pivot)).isEqualByComparingTo("70.00");
    }

    private Transaction saveTransaction(String key) {
        Transaction transaction = new Transaction();
        transaction.setUserId(1L);
        transaction.setSenderId(0L);
        transaction.setReceiverId(1L);
        transaction.setAmount(new BigDecimal("1.00"));
        transaction.setType(TransactionType.TOPUP);
        transaction.setStatus(TransactionStatus.SUCCESS);
        transaction.setIdempotencyKey(key);
        return transactionRepository.save(transaction);
    }

    private void saveEntry(Transaction transaction, Long userId, EntryType type, BigDecimal amount, LocalDateTime createdAt) {
        LedgerEntry entry = new LedgerEntry();
        entry.setTransaction(transaction);
        entry.setUserId(userId);
        entry.setEntryType(type);
        entry.setAmount(amount);
        entry.setCreatedAt(createdAt);
        ledgerEntryRepository.save(entry);
    }
}

