package com.wallet.userkyc.controller;

import org.junit.jupiter.api.Test;
import org.springframework.http.HttpStatus;
import org.springframework.web.multipart.MaxUploadSizeExceededException;

import java.util.Map;
import java.util.NoSuchElementException;

import static org.assertj.core.api.Assertions.assertThat;

class RestExceptionHandlerTest {

    private final RestExceptionHandler handler = new RestExceptionHandler();

    @Test
    void handleNotFound_returns404Payload() {
        Map<String, Object> body = handler.handleNotFound(new NoSuchElementException("missing")).getBody();

        assertThat(body).isNotNull();
        assertThat(body.get("status")).isEqualTo(HttpStatus.NOT_FOUND.value());
        assertThat(body.get("message")).isEqualTo("Resource not found");
    }

    @Test
    void handleIllegalArgument_returns400Payload() {
        Map<String, Object> body = handler.handleIllegalArgument(new IllegalArgumentException("bad input")).getBody();

        assertThat(body).isNotNull();
        assertThat(body.get("status")).isEqualTo(HttpStatus.BAD_REQUEST.value());
        assertThat(body.get("message")).isEqualTo("bad input");
    }

    @Test
    void handleFileTooLarge_returnsFriendlyMessage() {
        Map<String, Object> body = handler.handleFileTooLarge(new MaxUploadSizeExceededException(1L)).getBody();

        assertThat(body).isNotNull();
        assertThat(body.get("status")).isEqualTo(HttpStatus.BAD_REQUEST.value());
        assertThat(body.get("message")).isEqualTo("Uploaded file is too large");
    }
}

package com.wallet.userkyc.controller;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.wallet.userkyc.dto.KycStatusRequest;
import com.wallet.userkyc.entity.UserProfile;
import com.wallet.userkyc.security.JwtRoleValidator;
import com.wallet.userkyc.service.UserKycService;
import io.jsonwebtoken.JwtException;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.HttpHeaders;
import org.springframework.http.MediaType;
import org.springframework.mock.web.MockMultipartFile;
import org.springframework.test.web.servlet.MockMvc;

import java.util.List;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.eq;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.multipart;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.put;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.jsonPath;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@WebMvcTest(value = UserKycController.class, properties = {
        "spring.cloud.config.enabled=false",
        "spring.cloud.config.import-check.enabled=false",
        "spring.cloud.config.fail-fast=false",
        "spring.config.import=optional:configserver:",
        "eureka.client.enabled=false"
})
class UserKycControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @MockBean
    private UserKycService userKycService;

    @MockBean
    private JwtRoleValidator jwtRoleValidator;

    @Test
    void createUser_returnsCreated() throws Exception {
        UserProfile request = new UserProfile();
        request.setFullName("Alice");
        request.setEmail("alice@example.com");

        UserProfile response = new UserProfile();
        response.setId(1L);
        response.setFullName("Alice");

        when(userKycService.createUser(any(UserProfile.class))).thenReturn(response);

        mockMvc.perform(post("/api/users")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(request)))
                .andExpect(status().isCreated())
                .andExpect(jsonPath("$.id").value(1L))
                .andExpect(jsonPath("$.fullName").value("Alice"));
    }

    @Test
    void getUser_returnsUser() throws Exception {
        UserProfile response = new UserProfile();
        response.setId(2L);
        response.setAuthUserId(2L);

        when(userKycService.getUser(2L)).thenReturn(response);

        mockMvc.perform(get("/api/users/2"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.id").value(2L));
    }

    @Test
    void getUser_withInvalidId_returnsBadRequest() throws Exception {
        mockMvc.perform(get("/api/users/0"))
                .andExpect(status().isBadRequest())
                .andExpect(jsonPath("$.message").exists());
    }

    @Test
    void supportGetUser_returnsUser() throws Exception {
        UserProfile response = new UserProfile();
        response.setId(3L);

        when(userKycService.getUser(3L)).thenReturn(response);

        mockMvc.perform(get("/api/support/users/3"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.id").value(3L));
    }

    @Test
    void submitKyc_returnsUpdatedProfile() throws Exception {
        UserProfile response = new UserProfile();
        response.setId(5L);
        response.setKycDocumentId("DOC-123");

        when(userKycService.submitKyc(5L, "DOC-123")).thenReturn(response);

        mockMvc.perform(post("/api/kyc/submit/5").param("documentId", "DOC-123"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.kycDocumentId").value("DOC-123"));
    }

    @Test
    void submitKycWithFile_returnsUpdatedProfile() throws Exception {
        MockMultipartFile file = new MockMultipartFile(
                "document",
                "doc.pdf",
                "application/pdf",
                "dummy".getBytes()
        );

        UserProfile response = new UserProfile();
        response.setId(7L);
        response.setKycStatus("PENDING");

        when(userKycService.submitKycFile(eq(7L), any())).thenReturn(response);

        mockMvc.perform(multipart("/api/kyc/upload/7").file(file))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.kycStatus").value("PENDING"));
    }

    @Test
    void updateStatus_withAdminHeader_allowsUpdate() throws Exception {
        UserProfile response = new UserProfile();
        response.setId(10L);
        response.setKycStatus("APPROVED");

        when(userKycService.updateKycStatus(eq(10L), any(KycStatusRequest.class))).thenReturn(response);

        mockMvc.perform(put("/api/kyc/10/status")
                        .header("X-Authenticated-Role", "ADMIN")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new KycStatusRequest("APPROVED", "ok"))))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.kycStatus").value("APPROVED"));
    }

    @Test
    void updateStatus_withNonAdminToken_returnsForbidden() throws Exception {
        when(jwtRoleValidator.extractRole("bad-token")).thenThrow(new JwtException("invalid"));

        mockMvc.perform(put("/api/kyc/10/status")
                        .header(HttpHeaders.AUTHORIZATION, "Bearer bad-token")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(new KycStatusRequest("APPROVED", "ok"))))
                .andExpect(status().isForbidden());
    }

    @Test
    void pendingKyc_withBearerAdmin_returnsList() throws Exception {
        UserProfile profile = new UserProfile();
        profile.setId(22L);
        when(jwtRoleValidator.extractRole("token-admin")).thenReturn("ADMIN");
        when(userKycService.pendingKyc()).thenReturn(List.of(profile));

        mockMvc.perform(get("/api/kyc/pending").header(HttpHeaders.AUTHORIZATION, "Bearer token-admin"))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$[0].id").value(22L));

        verify(jwtRoleValidator).extractRole("token-admin");
    }
}

package com.wallet.userkyc.dto;

import org.junit.jupiter.api.Test;

import static org.assertj.core.api.Assertions.assertThat;

class DtoRecordsTest {

    @Test
    void kycStatusRequest_recordContract() {
        KycStatusRequest request1 = new KycStatusRequest("APPROVED", "ok");
        KycStatusRequest request2 = new KycStatusRequest("APPROVED", "ok");

        assertThat(request1.status()).isEqualTo("APPROVED");
        assertThat(request1.reason()).isEqualTo("ok");
        assertThat(request1).isEqualTo(request2);
        assertThat(request1.hashCode()).isEqualTo(request2.hashCode());
        assertThat(request1.toString()).contains("APPROVED");
    }

    @Test
    void kycVerifyRequest_recordContract() {
        KycVerifyRequest request = new KycVerifyRequest(77L, "DOC-77");

        assertThat(request.userId()).isEqualTo(77L);
        assertThat(request.documentRef()).isEqualTo("DOC-77");
        assertThat(request.toString()).contains("DOC-77");
    }

    @Test
    void kycVerifyResponse_recordContract() {
        KycVerifyResponse response = new KycVerifyResponse("ref-1", "VERIFIED", "done");

        assertThat(response.verificationRef()).isEqualTo("ref-1");
        assertThat(response.status()).isEqualTo("VERIFIED");
        assertThat(response.providerMessage()).isEqualTo("done");
    }

    @Test
    void notificationEvent_recordContract() {
        NotificationEvent event1 = new NotificationEvent(5L, "KYC_STATUS_UPDATE", "EMAIL", "x@y.com", "approved");
        NotificationEvent event2 = new NotificationEvent(5L, "KYC_STATUS_UPDATE", "EMAIL", "x@y.com", "approved");

        assertThat(event1.userId()).isEqualTo(5L);
        assertThat(event1.eventType()).isEqualTo("KYC_STATUS_UPDATE");
        assertThat(event1).isEqualTo(event2);
        assertThat(event1.hashCode()).isEqualTo(event2.hashCode());
    }
}

package com.wallet.userkyc.entity;

import org.junit.jupiter.api.Test;

import static org.assertj.core.api.Assertions.assertThat;

class UserProfileTest {

    @Test
    void gettersAndSetters_workForAllFields() {
        byte[] data = new byte[]{1, 2, 3};

        UserProfile profile = new UserProfile();
        profile.setId(1L);
        profile.setAuthUserId(9L);
        profile.setFullName("Demo User");
        profile.setEmail("demo@example.com");
        profile.setPhone("9999999999");
        profile.setKycStatus("PENDING");
        profile.setKycDocumentId("DOC-1");
        profile.setKycDocumentName("doc.pdf");
        profile.setKycDocumentContentType("application/pdf");
        profile.setKycProviderStatus("VERIFIED");
        profile.setKycProviderRef("ref-1");
        profile.setKycDocumentSize(123L);
        profile.setKycDocumentData(data);

        assertThat(profile.getId()).isEqualTo(1L);
        assertThat(profile.getAuthUserId()).isEqualTo(9L);
        assertThat(profile.getFullName()).isEqualTo("Demo User");
        assertThat(profile.getEmail()).isEqualTo("demo@example.com");
        assertThat(profile.getPhone()).isEqualTo("9999999999");
        assertThat(profile.getKycStatus()).isEqualTo("PENDING");
        assertThat(profile.getKycDocumentId()).isEqualTo("DOC-1");
        assertThat(profile.getKycDocumentName()).isEqualTo("doc.pdf");
        assertThat(profile.getKycDocumentContentType()).isEqualTo("application/pdf");
        assertThat(profile.getKycProviderStatus()).isEqualTo("VERIFIED");
        assertThat(profile.getKycProviderRef()).isEqualTo("ref-1");
        assertThat(profile.getKycDocumentSize()).isEqualTo(123L);
        assertThat(profile.getKycDocumentData()).containsExactly(1, 2, 3);
    }
}

