package com.wallet.userkyc.security;

import io.jsonwebtoken.JwtException;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.io.Encoders;
import io.jsonwebtoken.security.Keys;
import org.junit.jupiter.api.Test;

import javax.crypto.SecretKey;
import java.nio.charset.StandardCharsets;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

class JwtRoleValidatorTest {

    private static final String SECRET = Encoders.BASE64.encode("01234567890123456789012345678901".getBytes(StandardCharsets.UTF_8));

    @Test
    void extractRole_returnsUppercaseRoleFromJwt() {
        SecretKey key = Keys.hmacShaKeyFor("01234567890123456789012345678901".getBytes(StandardCharsets.UTF_8));
        String token = Jwts.builder().claim("role", "admin").signWith(key).compact();

        JwtRoleValidator validator = new JwtRoleValidator(SECRET);
        String role = validator.extractRole(token);

        assertThat(role).isEqualTo("ADMIN");
    }

    @Test
    void extractRole_withBlankToken_throwsJwtException() {
        JwtRoleValidator validator = new JwtRoleValidator(SECRET);

        assertThatThrownBy(() -> validator.extractRole(" "))
                .isInstanceOf(JwtException.class)
                .hasMessageContaining("missing");
    }

    @Test
    void constructor_withBlankSecret_throwsIllegalStateException() {
        assertThatThrownBy(() -> new JwtRoleValidator(" "))
                .isInstanceOf(IllegalStateException.class)
                .hasMessageContaining("security.jwt.secret");
    }
}

package com.wallet.userkyc.service;

import com.wallet.userkyc.dto.KycVerifyRequest;
import com.wallet.userkyc.dto.KycVerifyResponse;
import org.junit.jupiter.api.Test;
import org.springframework.cloud.openfeign.FeignClient;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestHeader;

import java.lang.reflect.Method;

import static org.assertj.core.api.Assertions.assertThat;

class IntegrationClientContractTest {

    @Test
    void feignClientAnnotation_hasExpectedServiceName() {
        FeignClient feignClient = IntegrationClient.class.getAnnotation(FeignClient.class);

        assertThat(feignClient).isNotNull();
        assertThat(feignClient.name()).isEqualTo("integration-service");
    }

    @Test
    void verifyKyc_contractAnnotationsArePresent() throws NoSuchMethodException {
        Method method = IntegrationClient.class.getMethod(
                "verifyKyc", String.class, KycVerifyRequest.class
        );

        PostMapping postMapping = method.getAnnotation(PostMapping.class);
        assertThat(postMapping).isNotNull();
        assertThat(postMapping.value()).containsExactly("/api/integrations/kyc/verify");

        assertThat(method.getParameterAnnotations()[0][0]).isInstanceOf(RequestHeader.class);
        assertThat(method.getParameterAnnotations()[1][0]).isInstanceOf(RequestBody.class);
        assertThat(method.getReturnType()).isEqualTo(KycVerifyResponse.class);
    }
}

package com.wallet.userkyc.service;

import com.wallet.userkyc.config.NotificationRabbitConfig;
import com.wallet.userkyc.dto.NotificationEvent;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.amqp.rabbit.core.RabbitTemplate;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.eq;
import static org.mockito.Mockito.doThrow;
import static org.mockito.Mockito.verify;

@ExtendWith(MockitoExtension.class)
class NotificationClientTest {

    @Mock
    private RabbitTemplate rabbitTemplate;

    @Test
    void sendSafe_publishesEvent() {
        NotificationClient client = new NotificationClient(rabbitTemplate);

        client.sendSafe(1L, "KYC_STATUS_UPDATE", "EMAIL", "a@b.com", "approved");

        verify(rabbitTemplate).convertAndSend(
                eq(NotificationRabbitConfig.NOTIFICATION_EXCHANGE),
                eq(NotificationRabbitConfig.NOTIFICATION_ROUTING_KEY),
                any(NotificationEvent.class)
        );
    }

    @Test
    void sendSafe_swallowsTemplateFailure() {
        NotificationClient client = new NotificationClient(rabbitTemplate);
        doThrow(new RuntimeException("rabbit down")).when(rabbitTemplate)
                .convertAndSend(eq(NotificationRabbitConfig.NOTIFICATION_EXCHANGE),
                        eq(NotificationRabbitConfig.NOTIFICATION_ROUTING_KEY), any(NotificationEvent.class));

        client.sendSafe(2L, "KYC_STATUS_UPDATE", "EMAIL", "c@d.com", "rejected");

        verify(rabbitTemplate).convertAndSend(
                eq(NotificationRabbitConfig.NOTIFICATION_EXCHANGE),
                eq(NotificationRabbitConfig.NOTIFICATION_ROUTING_KEY),
                any(NotificationEvent.class)
        );
    }
}

